// Behavioral Modeling
module mux2to1_behav (input A, B, S, output Y);
  always @ (*) begin
    if (S == 0)
      Y = A;
    else
      Y = B;
  end
endmodule

// Structural Modeling (using basic gates)
module mux2to1_struct (input A, B, S, output Y);
  wire S_bar, T1, T2;

  // NOT gate
  not (S_bar, S);

  // AND gates
  and (T1, S_bar, A);
  and (T2, S, B);

  // OR gate
  or (Y, T1, T2);

endmodule

// Testbench
module tb_mux;
  reg A, B, S;
  wire Y;

  mux2to1_behav uut (A, B, S, Y);

  initial begin
    $display("A B S | Y");
    $monitor("%b %b %b | %b", A, B, S, Y);
    A=0; B=0; S=0; #10;
    A=0; B=0; S=1; #10;
    A=0; B=1; S=0; #10;
    A=0; B=1; S=1; #10;
    A=1; B=0; S=0; #10;
    A=1; B=0; S=1; #10;
    A=1; B=1; S=0; #10;
    A=1; B=1; S=1; #10;
  end
endmodule

#include <stdio.h>
#include <stdbool.h>

// Evaluate AND gate
bool AND(bool a, bool b) {
    return a && b;
}

// Evaluate OR gate
bool OR(bool a, bool b) {
    return a || b;
}

// Evaluate NOT gate
bool NOT(bool a) {
    return !a;
}

// Evaluate F = A.B + C using gate functions
bool evaluateFunction(bool A, bool B, bool C) {
    // First compute A.B (AND of A and B)
    bool andResult = AND(A, B);
    // Then compute (A.B) + C (OR with C)
    bool result = OR(andResult, C);
    return result;
}

// Generate complete truth table
void generateTruthTable() {
    printf("A B C | F\n");
    printf("-----\n");

    for (int i = 0; i < 8; i++) {
        bool A = (i & 4) ? true : false;
        bool B = (i & 2) ? true : false;
        bool C = (i & 1) ? true : false;

        bool F = evaluateFunction(A, B, C);

        printf("%d %d %d | %d\n", A, B, C, F);
    }
}

int main() {
    generateTruthTable();
    return 0;
}
